CODE_EXAMPLE:
public class NHPP {
  public double GetRate(double t) {
    // Time-dependent rate function
    return 2.0 + 3.0 * Math.Sin(t / 10.0);
  }

  public int SimulateArrivals(double timeWindow) {
    int count = 0;
    for (double t = 0; t < timeWindow; t += 0.1) {
      if (Random.Shared.NextDouble() < GetRate(t) * 0.01) count++;
    }
    return count;
  }
}

UNIT_TEST_EXAMPLE:
[TestMethod]
public void GetRate_ReturnsPositiveRate() {
  var nhpp = new NHPP();
  double rate = nhpp.GetRate(5.0);
  Assert.IsTrue(rate > 0);
}

[TestMethod]
public void SimulateArrivals_ReturnsNonNegativeCount() {
  var nhpp = new NHPP();
  int count = nhpp.SimulateArrivals(100.0);
  Assert.IsTrue(count >= 0);
}
